SELECT AVG(rating) AS average_rating
FROM quality_ratings
WHERE evaluator_id = 1;

SELECT MIN(rating) AS lowest_quality_rating
FROM quality_ratings
WHERE evaluator_id = 1;

SELECT winery_name
FROM wineries
ORDER BY winery_name ASC;

SELECT winery_name
FROM wineries
ORDER BY winery_name;

SELECT AVG(rating) AS average_rating
FROM quality_ratings
WHERE evaluator_id = (SELECT evaluator_id FROM evaluators WHERE evaluator_name = 'John Doe');

SELECT winery_name, location
FROM wineries
WHERE winery_id = 0;
